{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and an alcohol (ethanol) in the presence of dry hydrogen chloride. This is the quintessential first step of the Pinner reaction, representing the core transformation without proceeding to subsequent hydrolysis or aminolysis steps, which are often considered separate reactions (e.g., Pinner amidine synthesis). The reactants are small, acyclic, and lack complex functional groups, making it a clear and unambiguous example.",
    "collision_avoidance_note": "The reactants are simple aliphatic molecules (acetonitrile and ethanol) to avoid overlap with reactions involving aromatic systems (e.g., Friedel-Crafts type reactions) or more complex functional groups. The product is the characteristic imino ether salt, which is specific to the Pinner reaction and distinct from products of other nitrile transformations like the Stephen reduction (aldehydes) or Blaise reaction (beta-ketoesters)."
  }
}
